member.example:
Bind the TMP_Text content using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextBinder _label;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _label;
    }


Bind the TMP_Text content by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextBinder Label =>
            new(_target);
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public string _label;
    }

Switch the TMP_Text content between two string values using a serialized binder field — the target TMP_Text is assigned in the Inspector.

    [View]
    public partial class ExampleView
    {
        [SerializeField]
        private TextSwitcherBinder _isEnabled;
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isEnabled;
    }


Switch the TMP_Text content between two string values by constructing the binder in code.

    [View]
    public partial class ExampleView
    {
        [SerializeField] private TMP_Text _target;
        
        private TextSwitcherBinder IsEnabled => new(
            _target, trueValue: "Enabled", falseValue: "Disabled");
    }
    
    [ViewModel]
    public partial class ExampleViewModel
    {
        [Bind] public bool _isEnabled;
    }
